{"path": "/tmp/sv-6b39d9aaa4b0407b95ac4f238ba3bf7c/Components/Pages/Catalog/CatalogFilters.razor", "file_text": "
<aside class="catalog-filters">
    <h2>Filters</h2>

    <div class="filter-section">
        <h3>Categories</h3>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <label class="filter-checkbox">
                    <input type="checkbox"
                           checked="@IsSelected(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    @category
                </label>
            }
        }
    </div>

    <div class="filter-section">
        <h3>Price Range</h3>
        <label>
            Min:
            <input type="number" min="0" step="0.01"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
        </label>
        <label>
            Max:
            <input type="number" min="0" step="0.01"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </label>
    </div>

    <div class="filter-section">
        <label class="filter-checkbox">
            <input type="checkbox" @bind="_inStockOnly" />
            In Stock Only
        </label>
    </div>

    <div class="filter-actions">
        <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
    </div>
</aside>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = default!;

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private List<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked && !_selectedCategories.Contains(category))
        {
            _selectedCategories.Add(category);
        }
        else if (!isChecked)
        {
            _selectedCategories.Remove(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? new List<string>(_selectedCategories) : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}
"}

{"path": "/tmp/sv-6b39d9aaa4b0407b95ac4f238ba3bf7c/Components/Pages/Catalog/CatalogToolbar.razor", "file_text": "
<div class="catalog-toolbar">
    <div class="sort-control">
        <label for="sort-select">Sort by:</label>
        <select id="sort-select" value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <div class="results-summary">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @start–@end of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}
"}

