+    font-size: 0.75rem;
+    border-radius: 4px;
+    margin-bottom: 0.5rem;
+}
+
+::deep .btn-add-to-cart {
+    width: 100%;
+    padding: 0.5rem;
+    background: #0d6efd;
+    color: white;
+    border: none;
+    border-radius: 4px;
+    cursor: pointer;
+    font-weight: 500;
+}
+
+::deep .btn-add-to-cart:hover:not(:disabled) {
+    background: #0b5ed7;
+}
+
+::deep .btn-add-to-cart:disabled {
+    background: #6c757d;
+    cursor: not-allowed;
+    opacity: 0.65;
+}
+
+/* Pagination */
+::deep .catalog-pagination {
+    display: flex;
+    justify-content: center;
+    gap: 0.5rem;
+    margin-top: 1.5rem;
+    padding: 1rem 0;
+}
+
+::deep .btn-page {
+    padding: 0.5rem 0.85rem;
+    border: 1px solid #dee2e6;
+    background: white;
+    border-radius: 4px;
+    cursor: pointer;
+    transition: background 0.15s;
+}
+
+::deep .btn-page:hover:not(:disabled) {
+    background: #e9ecef;
+}
+
+::deep .btn-page.active {
+    background: #0d6efd;
+    color: white;
+    border-color: #0d6efd;
+}
+
+::deep .btn-page:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+/* States */
+.loading-indicator {
+    text-align: center;
+    padding: 3rem;
+    color: #6c757d;
+}
+
+::deep .empty-results {
+    text-align: center;
+    padding: 3rem;
+    color: #6c757d;
+    background: #f8f9fa;
+    border-radius: 8px;
+}
+
+.alert-error {
+    padding: 1rem 1.5rem;
+    background: #f8d7da;
+    border: 1px solid #f5c2c7;
+    border-radius: 6px;
+    color: #842029;
+    margin-bottom: 1rem;
+}
+
+.alert-error button {
+    margin-top: 0.5rem;
+    padding: 0.4rem 1rem;
+    background: #842029;
+    color: white;
+    border: none;
+    border-radius: 4px;
+    cursor: pointer;
+}
+

